    }

    if (-not $data.PSObject.Properties.Match('tests')) {
        throw "JSON file '$Path' is missing required 'tests' array"
    }
    if ($null -eq $data.tests) {
        throw "JSON file '$Path' has a null 'tests' array"
    }

