        }
        $failureMsg = $null
        if ($t.PSObject.Properties.Match('failureMessage')) {
            $failureMsg = $t.failureMessage
        }
        $suite = ''
        if ($t.PSObject.Properties.Match('suite')) { $suite = [string]$t.suite }
        elseif ($t.PSObject.Properties.Match('classname')) { $suite = [string]$t.classname }

